#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[1000001];
        scanf("%s", S);
        int n = strlen(S);
        int count = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i; j < n; j++) {
                int num = atoi(S + i);
                if ((S[i] == '0' && j > i) || num % 8 == 0) {
                    if (S[i] != '0' || j == i) {
                        count++;
                    }
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

