        int n = S.length();
        int count = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i; j < n; j++) {
                string substr = S.substr(i, j - i + 1);
                int num = stoi(substr);
                if ((substr[0] == '0' && j > i) || num % 8 == 0) {
                    if (substr[0] != '0' || j == i) {
                        count++;
                    }
                }
            }
        }
        cout << count << endl;
    }
    return 0;
}

