import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String S = sc.next();
            int n = S.length();
            int count = 0;
            for (int i = 0; i < n; i++) {
                for (int j = i; j < n; j++) {
                    String substr = S.substring(i, j + 1);
                    int num = Integer.parseInt(substr);
                    if ((substr.charAt(0) == '0' && j > i) || num % 8 == 0) {
                        if (substr.charAt(0) != '0' || j == i) {
                            count++;
                        }
                    }
                }
            }
            System.out.println(count);
        }
    }
}

